template <class T, class posVecType>
inline T distance(const posVecType* position, const int i, const int j)
{
  posVecType ipos = position[i];
  posVecType jpos = position[j];
  T delx = ipos.x - jpos.x;
  T dely = ipos.y - jpos.y;
  T delz = ipos.z - jpos.z;
  T r2inv = delx * delx + dely * dely + delz * delz;
  return r2inv;
}

template <class T>
inline void insertInOrder(
  std::list<T>& currDist,
  std::list<int>& currList,
  const int j,
  const T distIJ,
  const int maxNeighbors)
{
  typename std::list<T>::iterator   it;
  typename std::list<int>::iterator it2;

  it2 = currList.begin();

  T currMax = currDist.back();

  if (distIJ > currMax) return;

  for (it = currDist.begin(); it != currDist.end(); it++)
  {
    if (distIJ < (*it))
    {
      currDist.insert(it, distIJ);
      currList.insert(it2, j);

      currList.resize(maxNeighbors);
      currDist.resize(maxNeighbors);
      return;
    }
    it2++;
  }
}

template <class T, class posVecType>
inline int buildNeighborList(const int nAtom, const posVecType* position,
    int* neighborList)
{
  int totalPairs = 0;

  for (int i = 0; i < nAtom; i++)
  {
    std::list<int> currList(maxNeighbors, -1);
    std::list<T> currDist(maxNeighbors, FLT_MAX);

    for (int j = 0; j < nAtom; j++)
    {
      if (i == j) continue;

      T distIJ = distance<T, posVecType>(position, i, j);
      insertInOrder<T>(currDist, currList, j, distIJ, maxNeighbors);
    }

    totalPairs += populateNeighborList<T>(currDist, currList, i, nAtom,
        neighborList);
  }
  return totalPairs;
}

template <class T>
inline int populateNeighborList(
    std::list<T>& currDist,
    std::list<int>& currList,
    const int i,
    const int nAtom,
    int* neighborList)
{
  int idx = 0;
  int validPairs = 0;

  typename std::list<T>::iterator distanceIter = currDist.begin();
  for (std::list<int>::iterator neighborIter = currList.begin();
      neighborIter != currList.end(); neighborIter++)
  {
    neighborList[(idx * nAtom) + i] = *neighborIter;

    if (*distanceIter < cutsq)
      validPairs++;

    idx++;
    distanceIter++;
  }
  return validPairs;
}

template <class T, class forceVecType, class posVecType>
bool checkResults(forceVecType* d_force, posVecType *position,
    int *neighList, int nAtom)
{
  T max_error = 0;
  for (int i = 0; i < nAtom; i++)
  {
    posVecType ipos = position[i];
    forceVecType f = zero;
    int j = 0;
    while (j < maxNeighbors)
    {
      int jidx = neighList[j*nAtom + i];

      posVecType jpos = position[jidx];

      T delx = ipos.x - jpos.x;
      T dely = ipos.y - jpos.y;
      T delz = ipos.z - jpos.z;
      T r2inv = delx*delx + dely*dely + delz*delz;

      if (r2inv > 0 && r2inv < cutsq) {
        r2inv = (T)1.0/r2inv;
        T r6inv = r2inv * r2inv * r2inv;
        T force = r2inv*r6inv*(lj1*r6inv - lj2);

        f.x += delx * force;
        f.y += dely * force;
        f.z += delz * force;
      }
      j++;
    }

    assert(std::isnan(d_force[i].x) == false);
    assert(std::isnan(d_force[i].y) == false);
    assert(std::isnan(d_force[i].z) == false);
    T fxe = std::fabs(f.x - d_force[i].x);
    T fye = std::fabs(f.y - d_force[i].y);
    T fze = std::fabs(f.z - d_force[i].z);
    if (fxe > max_error) max_error = fxe;
    if (fye > max_error) max_error = fye;
    if (fze > max_error) max_error = fze;
  }
  std::cout << "Max error between host and device: " << max_error << "\n";
  return true;
}

static inline void md(
  const POSVECTYPE* __restrict__ position,
        FORCEVECTYPE* __restrict__ force,
  const int* __restrict__ neighborList,
  const int nAtom,
  const int maxNeighbors_t,
  const FPTYPE lj1_t,
  const FPTYPE lj2_t,
  const FPTYPE cutsq_t)
{
#pragma omp target teams distribute parallel for is_device_ptr(position, force, neighborList)
  for (int idx = 0; idx < nAtom; idx++)
  {
    POSVECTYPE ipos = position[idx];
    FORCEVECTYPE f = zero;

    int j = 0;
    while (j < maxNeighbors_t)
    {
      int jidx = neighborList[j*nAtom + idx];

      POSVECTYPE jpos = position[jidx];

      FPTYPE delx = ipos.x - jpos.x;
      FPTYPE dely = ipos.y - jpos.y;
      FPTYPE delz = ipos.z - jpos.z;
      FPTYPE r2inv = delx*delx + dely*dely + delz*delz;

      if (r2inv > 0 && r2inv < cutsq_t)
      {
        r2inv = (FPTYPE)1.0 / r2inv;
        FPTYPE r6inv = r2inv * r2inv * r2inv;
        FPTYPE forceC = r2inv * r6inv * (lj1_t * r6inv - lj2_t);

        f.x += delx * forceC;
        f.y += dely * forceC;
        f.z += delz * forceC;
      }
      j++;
    }
    force[idx] = f;
  }
}

int main(int argc, char** argv)
{
  if (argc != 3) {
    std::cout << "Usage: ./" << argv[0] << " <class size> <iteration>\n";
    return 1;
  }

  int sizeClass = atoi(argv[1]);
  int iteration = atoi(argv[2]);
  const int probSizes[] = { 12288, 24576, 36864, 73728 };
  assert(sizeClass >= 0 && sizeClass < 4);
  assert(iteration >= 0);

  int nAtom = probSizes[sizeClass];

  POSVECTYPE* position = (POSVECTYPE*) malloc(nAtom * sizeof(POSVECTYPE));
  FORCEVECTYPE* h_force = (FORCEVECTYPE*) malloc(nAtom * sizeof(FORCEVECTYPE));
  int *neighborList = (int*) malloc(maxNeighbors * nAtom * sizeof(int));

  std::cout << "Initializing test problem (this can take several minutes for large problems).\n";

  srand(123);

  for (int i = 0; i < nAtom; i++)
  {
    position[i].x = rand() % domainEdge;
    position[i].y = rand() % domainEdge;
    position[i].z = rand() % domainEdge;
    position[i].w = 0;
  }

  std::cout << "Finished.\n";
  int totalPairs = buildNeighborList<FPTYPE, POSVECTYPE>(nAtom, position, neighborList);
  std::cout << totalPairs << " of " << nAtom*maxNeighbors << " pairs within cutoff distance = "
       << 100.0 * ((double)totalPairs / (nAtom*maxNeighbors)) << " %\n";

  int device = omp_get_default_device();
  int host = omp_get_initial_device();

  POSVECTYPE*   d_position = (POSVECTYPE*)omp_target_alloc(nAtom * sizeof(POSVECTYPE), device);
  FORCEVECTYPE* d_force = (FORCEVECTYPE*)omp_target_alloc(nAtom * sizeof(FORCEVECTYPE), device);
  int* d_neighborList = (int*)omp_target_alloc(nAtom * maxNeighbors * sizeof(int), device);

  omp_target_memcpy(d_position, position, nAtom * sizeof(POSVECTYPE), 0, 0, device, host);
  omp_target_memcpy(d_neighborList, neighborList, nAtom * maxNeighbors * sizeof(int), 0, 0, device, host);

  md(d_position, d_force, d_neighborList, nAtom, maxNeighbors, lj1, lj2, cutsq);

  omp_target_memcpy(h_force, d_force, nAtom * sizeof(FORCEVECTYPE), 0, 0, host, device);

  std::cout << "Performing Correctness Check (may take several minutes)\n";
  checkResults<FPTYPE, FORCEVECTYPE, POSVECTYPE>(h_force, position, neighborList, nAtom);

  auto start = std::chrono::steady_clock::now();

  for (int j = 0; j < iteration; j++)
  {
    md(d_position, d_force, d_neighborList, nAtom, maxNeighbors, lj1, lj2, cutsq);
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average kernel execution time " << (time * 1e-9f) / iteration << " (s)\n";

  omp_target_free(d_position, device);
  omp_target_free(d_force, device);
  omp_target_free(d_neighborList, device);

  free(position);
  free(h_force);
  free(neighborList);

  return 0;
}
